const baseConfig = $('Config Reporte').first().json;
const triggerConfig = $('SetTrigger - Flujo').first()?.json || {};
const mergedFlags = { ...(baseConfig.flags || {}) };
function mergeFlag(name) {
  const value = triggerConfig[name];
  if (value === undefined || value === null || value === '') return;
  if (typeof value === 'boolean') mergedFlags[name] = value;
  else if (typeof value === 'number') mergedFlags[name] = value !== 0;
  else {
    const text = String(value).trim().toLowerCase();
    if (['true','1','yes','y','si','s','on','enabled'].includes(text)) mergedFlags[name] = true;
    else if (['false','0','no','n','off','disabled'].includes(text)) mergedFlags[name] = false;
  }
}
for (const key of ['include_attachment','include_detail','include_summary','include_operational_notes','include_itop_button_footer','send_email','include_requirements','include_incidents','include_changes','include_problems']) mergeFlag(key);
const config = { ...baseConfig, ...triggerConfig, flags: mergedFlags };
for (const [key, value] of Object.entries(mergedFlags)) config[key] = value;
const company = String(config.Company || config.company || 'TecnoComp').trim();
const itopOrganization = String(config.itop_organization || '').trim();

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}


function csvEscape(value) {
  const text = String(value ?? '').replace(/"/g, '""');
  return `"${text}"`;
}

function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return fallback;
}

function flattenInput(items) {
  const rows = [];
  for (const item of items) {
    const j = item.json || {};
    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) {
        rows.push({ key, ...(value || {}), fields: value?.fields || value || {} });
      }
      continue;
    }
    if (Array.isArray(j)) { rows.push(...j); continue; }
    rows.push(j);
  }
  return rows;
}

function scalarText(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    const text = String(value).trim();
    return text === '[object Object]' ? '' : text;
  }
  return '';
}

function cleanContactText(value) {
  let text = scalarText(value);
  if (!text) return '';
  // iTop suele exponer la relación como "Contacto / Activo".
  // Para el reporte se requiere solamente el contacto.
  if (text.includes(' / ')) text = text.split(' / ')[0].trim();
  return text;
}

function normalizeContactEntry(entry) {
  if (entry === undefined || entry === null) return '';

  const direct = cleanContactText(entry);
  if (direct) return direct;

  if (Array.isArray(entry)) {
    return entry.map(normalizeContactEntry).filter(Boolean).join(', ');
  }

  if (typeof entry === 'object') {
    if (entry.fields && typeof entry.fields === 'object') {
      const fromFields = normalizeContactEntry(entry.fields);
      if (fromFields) return fromFields;
    }

    if (entry.objects && typeof entry.objects === 'object') {
      return Object.values(entry.objects).map(normalizeContactEntry).filter(Boolean).join(', ');
    }

    const preferredFields = [
      'contact_id_friendlyname',
      'person_id_friendlyname',
      'user_id_friendlyname',
      'contact_name',
      'person_name',
      'display_name',
      'name',
      'friendlyname',
      'email',
      'email_address',
    ];

    for (const field of preferredFields) {
      const text = cleanContactText(entry[field]);
      if (text) return text;
    }

    const nestedCandidates = ['contact_id', 'person_id', 'user_id', 'contact', 'person', 'user'];
    for (const field of nestedCandidates) {
      const text = normalizeContactEntry(entry[field]);
      if (text) return text;
    }
  }

  return '';
}

function normalizeContacts(value) {
  const text = normalizeContactEntry(value);
  if (!text) return '';

  const unique = [];
  const seen = new Set();
  for (const part of text.split(',').map(v => cleanContactText(v)).filter(Boolean)) {
    const key = part.toLowerCase();
    if (!seen.has(key)) {
      seen.add(key);
      unique.push(part);
    }
  }
  return unique.join(', ');
}

function isBlankValue(value) {
  const v = String(value ?? '').trim();
  return !v || v === '-' || v.toLowerCase() === 'n/a' || v.toLowerCase() === 'null' || v.toLowerCase() === 'undefined' || v.toLowerCase() === 'sin bodega/localidad';
}

function inferWorkstationClass(f) {
  // iTop estándar puede mostrar la clase como "PC/Laptop" sin separar notebook de desktop.
  // La separación real depende de que exista algún dato útil: tipo, categoría, modelo, nombre o descripción.
  const rawHints = [
    getField(f, ['finalclass', 'class', 'class_friendlyname'], ''),
    getField(f, ['type', 'type_friendlyname', 'computer_type', 'computer_type_friendlyname', 'device_type', 'device_type_friendlyname'], ''),
    getField(f, ['category', 'category_friendlyname', 'subcategory', 'subcategory_friendlyname'], ''),
    getField(f, ['name', 'friendlyname'], ''),
    getField(f, ['model_id_friendlyname', 'model'], ''),
    getField(f, ['brand_id_friendlyname', 'brand'], ''),
    getField(f, ['description', 'comment', 'comments'], ''),
  ].map(v => String(v || '').trim()).filter(Boolean);

  const hint = rawHints.join(' ').toLowerCase();

  const laptopPatterns = [
    'laptop', 'notebook', 'portable', 'portatil', 'portátil', 'ultrabook',
    'latitude', 'elitebook', 'probook', 'thinkpad', 'thinkbook', 'macbook',
    'vivobook', 'zenbook', 'travelmate', 'tecra', 'xps 13', 'xps 15',
    // Patrones frecuentes de modelos corporativos notebook. Ajustar según catálogo real de la CMDB.
    /\b(34|35|54|55|72|73|74|75)[0-9]{2}\b/,
    /\bt14\b/, /\bt15\b/, /\bx1\b/, /\be14\b/, /\be15\b/
  ];

  const desktopPatterns = [
    'desktop', 'sobremesa', 'escritorio', 'tower', 'torre', 'sff', 'micro',
    'minitower', 'optiplex', 'prodesk', 'elitedesk', 'thinkcentre',
    'workstation', 'all-in-one', 'all in one', 'aio'
  ];

  for (const pattern of desktopPatterns) {
    if (hint.includes(pattern)) return 'PC';
  }

  for (const pattern of laptopPatterns) {
    if (pattern instanceof RegExp ? pattern.test(hint) : hint.includes(pattern)) return 'Laptop';
  }

  return 'PC/Laptop';
}

function normalizeClass(value, f = {}) {
  const raw = String(value || '-').trim();
  const lower = raw.toLowerCase();

  if (lower === 'pc' || lower === 'pc/laptop' || lower.includes('pc/laptop') || lower.includes('desktop') || lower.includes('laptop') || lower.includes('notebook') || lower.includes('portable')) {
    return inferWorkstationClass({ ...f, finalclass: raw });
  }

  if (lower === 'mobilephone' || lower.includes('phone') || lower.includes('telefono') || lower.includes('teléfono')) return 'Teléfonos móviles';
  if (lower === 'tablet') return 'Tablets';
  if (lower === 'printer' || lower.includes('impresora')) return 'Impresoras';
  if (lower === 'peripheral' || lower.includes('periferico') || lower.includes('periférico')) return 'Periféricos';
  return raw || 'Otros';
}

function classSortWeight(className) {
  const order = { 'PC': 10, 'Laptop': 20, 'PC/Laptop': 25, 'Tablets': 30, 'Teléfonos móviles': 40, 'Impresoras': 50, 'Periféricos': 60, 'Otros': 90 };
  return order[className] || 80;
}

function normalizeStatus(value) {
  const raw = String(value || '').trim();
  const s = raw.toLowerCase();

  if (s === 'stock' || s.includes('stock') || s.includes('inventario') || s.includes('available')) {
    return { code: 'stock', label: 'En Inventario' };
  }
  if (s === 'implementation' || s.includes('implementation') || s.includes('implementacion') || s.includes('implementación') || s.includes('no productivo')) {
    return { code: 'implementation', label: 'No Productivo' };
  }
  if (s === 'production' || s.includes('production') || s.includes('produccion') || s.includes('producción') || s.includes('productivo')) {
    return { code: 'production', label: 'Productivo' };
  }
  if (s === 'obsolete' || s.includes('obsolete') || s.includes('obsoleto') || s.includes('retired')) {
    return { code: 'obsolete', label: 'Obsoleto' };
  }

  return { code: raw || 'unknown', label: raw || 'Sin estado' };
}

function statusSortWeight(code) {
  const order = { stock: 10, implementation: 20, production: 30, obsolete: 40 };
  return order[code] || 90;
}

function statusBadge(status) {
  const code = status.code;
  const label = status.label;
  if (code === 'stock') return badge(label, 'blue');
  if (code === 'implementation') return badge(label, 'orange');
  if (code === 'production') return badge(label, 'green');
  if (code === 'obsolete') return badge(label, 'gray');
  return badge(label, 'gray');
}

function parseDate(value) {
  if (!value || value === '-') return null;
  const d = new Date(String(value).replace(' ', 'T'));
  if (Number.isNaN(d.getTime())) return null;
  return d;
}

function fmtDateOnly(value) {
  const d = parseDate(value);
  if (!d) return isBlankValue(value) ? '-' : String(value);
  return d.toLocaleDateString('es-CL', {
    timeZone: config.timezone || 'America/Santiago',
    year: 'numeric', month: '2-digit', day: '2-digit'
  });
}

function isWarrantyExpired(value) {
  const d = parseDate(value);
  if (!d) return false;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  return d < today;
}

function badge(text, color = 'gray') {
  return `<span class="badge badge-${color}">${escapeHtml(text)}</span>`;
}

function td(value, align = 'left') {
  return `<td align="${align}" style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${value}</td>`;
}

function headerCell(text) {
  return `<th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec; white-space:nowrap;">${escapeHtml(text)}</th>`;
}

function reviewReasons(asset) {
  const reasons = [];
  if (isBlankValue(asset.serial)) reasons.push('sin serie');
  if (isBlankValue(asset.brand)) reasons.push('sin marca');
  if (isBlankValue(asset.model)) reasons.push('sin modelo');
  if (isBlankValue(asset.location) || asset.location === 'Sin bodega/localidad') reasons.push('sin bodega/localidad');
  if (isWarrantyExpired(asset.warrantyEnd)) reasons.push('garantía vencida');
  return reasons;
}

const rawRows = flattenInput($input.all());

const allAssets = rawRows.map((row) => {
  const f = row.fields || row;
  const contactRaw = getField(f, [
    'contacts_list_friendlyname',
    'contacts_list',
    'contact_id_friendlyname',
    'contact_name',
    'person_id_friendlyname',
    'user_id_friendlyname'
  ], '');
  const status = normalizeStatus(getField(f, ['operational_status_friendlyname', 'operational_status', 'status_friendlyname', 'status'], '-'));
  const finalclassRaw = getField(f, ['finalclass', 'class', 'class_friendlyname'], '-');

  return {
    name: getField(f, ['name', 'friendlyname'], '-'),
    finalclass: normalizeClass(finalclassRaw, f),
    finalclassRaw,
    status,
    organization: getField(f, ['org_id_friendlyname', 'organization_name', 'org_name'], '-'),
    location: getField(f, ['location_id_friendlyname', 'location_name', 'location_id'], 'Sin bodega/localidad'),
    contacts: normalizeContacts(contactRaw),
    brand: getField(f, ['brand_id_friendlyname', 'brand'], '-'),
    model: getField(f, ['model_id_friendlyname', 'model'], '-'),
    serial: getField(f, ['serialnumber', 'serial_number'], ''),
    move2production: getField(f, ['move2production', 'production_date'], '-'),
    purchaseDate: getField(f, ['purchase_date'], '-'),
    warrantyEnd: getField(f, ['end_of_warranty'], '-'),
  };
});

// Requisito del reporte: devolver solamente activos CMDB con contacto asignado.
const assets = allAssets
  .filter(asset => !isBlankValue(asset.contacts))
  .sort((a, b) =>
    statusSortWeight(a.status.code) - statusSortWeight(b.status.code) ||
    String(a.status.label).localeCompare(String(b.status.label), 'es') ||
    classSortWeight(a.finalclass) - classSortWeight(b.finalclass) ||
    String(a.finalclass).localeCompare(String(b.finalclass), 'es') ||
    String(a.location).localeCompare(String(b.location), 'es') ||
    String(a.name).localeCompare(String(b.name), 'es')
  );

const statusGroups = new Map();
const classGroups = new Map();
const locationGroups = new Map();
const reviewAssets = [];
let warrantyExpiredCount = 0;

for (const asset of assets) {
  if (!statusGroups.has(asset.status.code)) statusGroups.set(asset.status.code, { status: asset.status, list: [] });
  statusGroups.get(asset.status.code).list.push(asset);

  if (!classGroups.has(asset.finalclass)) classGroups.set(asset.finalclass, []);
  classGroups.get(asset.finalclass).push(asset);

  if (!locationGroups.has(asset.location)) locationGroups.set(asset.location, []);
  locationGroups.get(asset.location).push(asset);

  if (isWarrantyExpired(asset.warrantyEnd)) warrantyExpiredCount++;
  const reasons = reviewReasons(asset);
  if (reasons.length) reviewAssets.push({ ...asset, reviewReasonText: reasons.join(', ') });
}

const statusEntries = Array.from(statusGroups.values()).sort((a, b) => statusSortWeight(a.status.code) - statusSortWeight(b.status.code) || a.status.label.localeCompare(b.status.label, 'es'));

const statusSummaryRows = statusEntries.map(({ status, list }) => {
  const byClass = {};
  for (const asset of list) byClass[asset.finalclass] = (byClass[asset.finalclass] || 0) + 1;
  const classText = Object.entries(byClass)
    .sort(([a], [b]) => classSortWeight(a) - classSortWeight(b) || a.localeCompare(b, 'es'))
    .map(([klass, count]) => `${escapeHtml(klass)}: ${count}`)
    .join('<br>');
  const reviewCount = list.filter(a => reviewReasons(a).length > 0).length;
  const observation = reviewCount > 0 ? `<span class="badge badge-yellow">Por revisar: ${reviewCount}</span>` : `<span class="badge badge-green">Sin observaciones</span>`;
  return `<tr>${td(statusBadge(status))}${td(`<strong>${list.length}</strong>`, 'right')}${td(classText || '-')}${td(observation)}</tr>`;
}).join('');

const locationSummaryRows = Array.from(locationGroups.entries()).sort(([a], [b]) => a.localeCompare(b, 'es')).map(([location, list]) => {
  const byStatus = {};
  for (const asset of list) byStatus[asset.status.label] = (byStatus[asset.status.label] || 0) + 1;
  const statusText = Object.entries(byStatus).sort(([a], [b]) => a.localeCompare(b, 'es')).map(([status, count]) => `${escapeHtml(status)}: ${count}`).join('<br>');
  const reviewCount = list.filter(a => reviewReasons(a).length > 0).length;
  const observation = reviewCount > 0 ? `<span class="badge badge-yellow">Por revisar: ${reviewCount}</span>` : `<span class="badge badge-green">Sin observaciones</span>`;
  return `<tr>${td(escapeHtml(location))}${td(`<strong>${list.length}</strong>`, 'right')}${td(statusText || '-')}${td(observation)}</tr>`;
}).join('');


function contactParts(value) {
  const text = String(value ?? '').trim();
  if (!text) return [];

  const unique = [];
  const seen = new Set();
  for (const part of text.split(',').map(v => cleanContactText(v)).filter(Boolean)) {
    const key = part.toLowerCase();
    if (!seen.has(key)) {
      seen.add(key);
      unique.push(part);
    }
  }
  return unique;
}

function renderContactsHtml(value) {
  const parts = contactParts(value);
  if (!parts.length) return '<span class="badge badge-yellow">Sin responsable</span>';
  if (parts.length === 1) return escapeHtml(parts[0]);

  // Para múltiples responsables se usa salto de línea sin viñetas/iconos,
  // compatible con clientes de correo como Outlook y Gmail.
  return parts
    .map(contact => `<div style="margin:0 0 3px 0; padding:0; color:#1f2937; font-size:12px; line-height:16px;">${escapeHtml(contact)}</div>`)
    .join('');
}

function assetRows(list, includeReviewColumn = false) {
  return list.map(asset => {
    const serialBadge = !isBlankValue(asset.serial) ? escapeHtml(asset.serial) : '<span class="badge badge-yellow">Sin serie</span>';
    const contactBadge = renderContactsHtml(asset.contacts);
    const warrantyValue = isWarrantyExpired(asset.warrantyEnd) ? '<span class="badge badge-orange">' + escapeHtml(fmtDateOnly(asset.warrantyEnd)) + '</span>' : escapeHtml(fmtDateOnly(asset.warrantyEnd));
    const reviewColumn = includeReviewColumn ? td(badge(asset.reviewReasonText || reviewReasons(asset).join(', '), 'yellow')) : '';
    return `<tr>
      ${td(`<strong>${escapeHtml(asset.name)}</strong>`)}
      ${td(statusBadge(asset.status))}
      ${td(escapeHtml(asset.location))}
      ${td(contactBadge)}
      ${td(escapeHtml(asset.brand))}
      ${td(escapeHtml(asset.model))}
      ${td(serialBadge)}
      ${td(escapeHtml(fmtDateOnly(asset.move2production)))}
      ${td(escapeHtml(fmtDateOnly(asset.purchaseDate)))}
      ${td(warrantyValue)}
      ${reviewColumn}
    </tr>`;
  }).join('');
}

function assetsTable(list, includeReviewColumn = false) {
  const reviewHead = includeReviewColumn ? headerCell('Criterio') : '';
  const colSpan = includeReviewColumn ? 11 : 10;
  return `<div class="table-scroll" style="width:100%; overflow-x:auto;">
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" class="data-table" style="width:100%;">
      <thead><tr>
        ${headerCell('Nombre')}${headerCell('Estado')}${headerCell('Bodega / localidad')}${headerCell('Contactos')}${headerCell('Marca')}${headerCell('Modelo')}${headerCell('N° serie')}${headerCell('Producción')}${headerCell('Compra')}${headerCell('Garantía')}${reviewHead}
      </tr></thead>
      <tbody>${list.length ? assetRows(list, includeReviewColumn) : `<tr><td colspan="${colSpan}" style="padding:12px; font-size:12px; color:#64748b;">Sin activos para listar.</td></tr>`}</tbody>
    </table>
  </div>`;
}

const statusAssetBlocks = statusEntries.map(({ status, list }) => {
  const classMap = new Map();

  for (const asset of list) {
    if (!classMap.has(asset.finalclass)) classMap.set(asset.finalclass, []);
    classMap.get(asset.finalclass).push(asset);
  }

  const classBlocks = Array.from(classMap.entries())
    .sort(([a], [b]) => classSortWeight(a) - classSortWeight(b) || a.localeCompare(b, 'es'))
    .map(([className, classList]) => `
      <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin:0 0 14px 0; border:1px solid #e2e8f0;">
        <tr>
          <td style="background-color:#f8fafc; padding:9px 12px; border-bottom:1px solid #e2e8f0;">
            <div style="font-size:13px; line-height:18px; font-weight:bold; color:#0f172a;">
              Clase/Tipo: ${escapeHtml(className)}
              <span style="color:#64748b; font-weight:normal;">(${classList.length} activos)</span>
            </div>
          </td>
        </tr>
        <tr><td>${assetsTable(classList, false)}</td></tr>
      </table>
    `).join('');

  return `
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:18px; border:1px solid #dbe3ec;">
      <tr><td style="background-color:#f1f5f9; padding:10px 12px;">
        <div style="font-size:14px; line-height:20px; font-weight:bold; color:#0f172a;">${statusBadge(status)} <span style="color:#64748b; font-weight:normal;">(${list.length} activos con contacto)</span></div>
        <div style="font-size:12px; line-height:18px; color:#64748b; margin-top:6px;">Grupo por estado operativo normalizado desde iTop, subagrupado por clase de activo.</div>
      </td></tr>
      <tr><td style="padding:12px;">${classBlocks}</td></tr>
    </table>
  `;
}).join('');

const reviewCriteria = [
  { title: 'Sin número de serie', description: 'Activos con contacto asignado, pero sin serial registrado en iTop.', match: (asset) => isBlankValue(asset.serial) },
  { title: 'Sin marca', description: 'Activos con contacto asignado, pero sin fabricante o marca asociada.', match: (asset) => isBlankValue(asset.brand) },
  { title: 'Sin modelo', description: 'Activos con contacto asignado, pero sin modelo técnico registrado.', match: (asset) => isBlankValue(asset.model) },
  { title: 'Sin bodega/localidad', description: 'Activos con contacto asignado, pero sin ubicación física clara para trazabilidad operacional.', match: (asset) => isBlankValue(asset.location) || asset.location === 'Sin bodega/localidad' },
  { title: 'Garantía vencida', description: 'Activos con fecha de vencimiento de garantía anterior a la fecha de generación del reporte.', match: (asset) => isWarrantyExpired(asset.warrantyEnd) },
];

const reviewAssetBlocks = reviewAssets.length ? reviewCriteria.map((criterion) => {
  const list = reviewAssets.filter(asset => criterion.match(asset)).sort((a, b) =>
    statusSortWeight(a.status.code) - statusSortWeight(b.status.code) ||
    classSortWeight(a.finalclass) - classSortWeight(b.finalclass) ||
    String(a.location).localeCompare(String(b.location), 'es') ||
    String(a.name).localeCompare(String(b.name), 'es')
  );
  if (!list.length) return '';
  return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:18px; border:1px solid #dbe3ec;">
    <tr><td style="background-color:#fff7ed; padding:10px 12px; border-bottom:1px solid #fed7aa;">
      <div style="font-size:14px; line-height:20px; font-weight:bold; color:#9a3412;">${escapeHtml(criterion.title)} <span style="color:#64748b; font-weight:normal;">(${list.length} activos)</span></div>
      <div style="font-size:12px; line-height:18px; color:#854d0e; margin-top:2px;">${escapeHtml(criterion.description)} Un mismo activo puede aparecer en más de un criterio si presenta múltiples condiciones de revisión.</div>
    </td></tr>
    <tr><td>${assetsTable(list, true)}</td></tr>
  </table>`;
}).join('') : '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #dbe3ec;"><tr><td style="padding:14px; font-size:13px; color:#166534;">No se detectaron activos por revisar según el criterio del reporte.</td></tr></table>';


const csvHeaders = [
  'Nombre',
  'Clase/Tipo',
  'Estado',
  'Bodega/Localidad',
  'Contactos',
  'Marca',
  'Modelo',
  'Serie',
  'Puesto en Produccion',
  'Fecha de Compra',
  'Vencimiento de Garantia'
];

const csvRows = assets.map(asset => [
  asset.name,
  asset.finalclass,
  asset.status.label,
  asset.location,
  asset.contacts,
  asset.brand,
  asset.model,
  asset.serial,
  fmtDateOnly(asset.move2production),
  fmtDateOnly(asset.purchaseDate),
  fmtDateOnly(asset.warrantyEnd)
]);

const csvContent = '\uFEFF' + [
  csvHeaders.map(csvEscape).join(';'),
  ...csvRows.map(row => row.map(csvEscape).join(';')),
].join('\r\n');

const generatedAt = new Date().toLocaleString('es-CL', {
  timeZone: config.timezone || 'America/Santiago',
  year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit'
});


const countByStatus = (code) => statusGroups.get(code)?.list.length || 0;

